SELECT usage_date, num_executions, execution_time, usage_status, model_id, tool_id
FROM model_usage
WHERE usage_status = 'success';

SELECT SUM(num_executions) AS total_executions
FROM model_usage
WHERE model_id = 0;

SELECT tool_name
FROM software_tools
WHERE category = 'Simulation';

SELECT COUNT(*) AS total_simulation_tools
FROM software_tools
WHERE category = 'Simulation';

SELECT COUNT(*) 
FROM simulation_models 
WHERE fmu_enabled = 1;

SELECT tool_name
FROM software_tools
WHERE tool_id = 0;

SELECT owner_id, COUNT(*) AS model_count
FROM simulation_models
GROUP BY owner_id;

SELECT value
FROM model_metadata
WHERE key = 'Sector';
